mapper.select:
SELECT b.id AS question_id, b.question_name, b.question_type, b.answerA, b.answerB, b.answerC, b.answerD, b.answerE, b.answerF, b.answer_parse, b.right_answers, a.my_answers, c.course_type FROM xm_practice_wrong a LEFT JOIN xm_course_question b ON a.question_id = b.id LEFT JOIN xm_course c ON b.course_id = c.id WHERE a.person_id = #{personId} AND b.is_delete = 0
AND c.course_type = #{courseType}
ORDER BY a.create_time DESC
